<template>
    <BaseModal name="loader" :full="true">
        <template v-slot:content>
            <div class="merge-accounts-box"
            >
                <div :style="{
                        'background-image': `url(${baseUrl}/themes/${theme}/accounts/main.jpg)`,
                        'background-color': 'var(--white-500)'
                    }"
                >

                    <template v-if="data.step === 'main'">
                        <label class="title" v-html="t('pages.settings.accounts.subtitle')"></label>
                        <div class="description">{{ t('pages.settings.accounts.description') }}</div>
                    </template>

                    <template v-if="data.step === 'get'">
                        <label class="title" v-html="t('pages.settings.accounts.get.title')"></label>

                        <div class="description">{{ t('pages.settings.accounts.get.description') }}</div>
                        <div class="instruction">{{ t('pages.settings.accounts.get.instruction', {
                            name: data.newProviders.map(item => t(`pages.settings.accounts.${item.toLowerCase()}`)).join(', ') 
                        }) }}</div>

                        <label class="code">{{ data.code }}</label>
                    </template>

                    <template v-if="data.step === 'send'">
                        <label class="title" v-html="t('pages.settings.accounts.send.title')"></label>

                        <div class="description">{{ t('pages.settings.accounts.send.description') }}</div>
                        <div class="warning">{{ t('pages.settings.accounts.send.warning', {
                        }) }}</div>
                    </template>
                </div>

                <div>
                    <div class="enter-box" v-if="data.step === 'main'">
                        <Button :name="t('pages.settings.accounts.get.title')"
                            :loading="data.loading"
                            @click="getCode"
                        />

                        <Button :name="t('pages.settings.accounts.send.title')"
                            :disabled="data.loading"
                            @click="sendCode"
                        />
                        <Button :name="t('common.close')"
                            :disabled="data.loading"
                            class="secondary"
                            @click="close"
                        />
                    </div>

                    <div class="enter-box" v-if="data.step === 'get'">
                        <Button :name="t('common.back')" class="secondary" @click="back" />
                    </div>

                    <div class="enter-box" v-if="data.step === 'send'">
                        <Button :name="t('pages.settings.accounts.send.button')"
                            @click="inputCode"
                        />

                        <Button :name="t('common.back')"
                            class="secondary"
                            @click="back"
                        />
                    </div>
                </div>
            </div>
        </template>
    </BaseModal>
</template>

<script setup>
import { reactive, computed } from 'vue';
import { useI18n } from 'vue-i18n';

import BaseModal from '🔗/components/modals/BaseModal.vue';
import Loader from '🔗/components/ui/Loader.vue';
// import Steps from '🔗/components/ui/Steps.vue';
import Button from '🔗/components/ui/Button.vue';

import api from '🔗/api';
import { storeToRefs } from 'pinia';
import stores from '@/stores';
import { baseUrl } from '🔗/utils/utils';
import { copyText, message, delay } from '🔗/utils/utils';

const others = stores.others();
const messengers = stores.messengers();
const user = stores.user();
const { theme } = storeToRefs(others);

const modals = stores.modals();


const { t } = useI18n();


const data = reactive({
    step: 'main',
    loading: false,
    code: null,
    token: null,
    newProviders: []
});

const showSuccess = async () => {
    user.me();

    modals.open('success', {
        data: {
            title: t('pages.settings.accounts.get.done'),
            close: t('common.close')
        },
        callback: () => {
            close();
        }
    });
}

const checkCode = async () => {
    clearTimeout(data.getTimeout);

    data.getTimeout = setTimeout(async () => {
        const result = await api.user().checkMergeRequest({
            value: data.code,
            token: data.token
        });


        if (result) {
            showSuccess();
            return
        }

        checkCode();
    }, 1000);
}

const getCode = async () => {
    data.loading = true;

    modals.open('loader', {data: { light: true }})

    const result = await api.user().createMergeRequest();

    if (!result?.value) {
        data.loading = false;
        return;
    }


    await delay(400);


    data.newProviders = ['MAX', 'telegram'].filter(item => !user.providers.includes(item));

    data.code = result.value;
    data.token = result.token;
    data.step = 'get';

    data.loading = false;
    modals.close('loader');

    copyText(data.code);
    message.success(t('pages.settings.accounts.get.copied'));

    checkCode();
}


const verifyCode = async (code) => {
    const payload = await api.user().sendMergeRequest({
        code
    });

    if (!payload) {
        await delay(500);
        message.info(t('pages.settings.accounts.send.error'))
        return;
    }

    await delay(1000);
    user.me();

    modals.open('success', {
        data: {
            title: t('pages.settings.accounts.send.done'),
            close: t('common.close')
        },
        callback: () => {
            close();
        }
    });

    return true;
}

const inputCode = async () => {
    modals.open('code', {
        data: {
            title: t('pages.settings.accounts.send.title'),
            description: t('pages.settings.accounts.send.instruction'),
            verify: t('pages.settings.accounts.send.accept'),
            check: async (code) => {
                return await verifyCode(code);
            }
        }
    });
};

const sendCode = async () => {
    data.step = 'send';
}

const back = async () => {
    clearTimeout(data.getTimeout);
    data.step = 'main';
    data.loading = false;
    data.code = null;
}



const close = () => {
    clearTimeout(data.getTimeout);
    modals.close('merge-accounts');
}
</script>

<style lang="scss" scoped>
    .merge-accounts-box {
        position: fixed;
        left: 0;
        top: 0;
        right: 0;
        bottom: 0;
        background: var(--white-500);
        @include fade-center;

        & > div {
            position: absolute;
            left: 0;
            right: 0;
            top: 0;
            bottom: 0;
            border-color: var(--white-500);
            background-size: cover;
            background-position: right bottom;
            padding: 100px 20px 40px 20px;
            display: flex;
            align-items: start;
            flex-direction: column;
            gap: 20px;
            opacity: 0;
            animation: fadeIn .2s forwards; 

            &:last-child:before {
                content: '';
                position: absolute;
                left: 0;
                top: 0;
                bottom: 0;
                right: 0;
                background: linear-gradient(180deg, rgba(0, 0, 0, 0) 0%, rgba(0, 0, 0, 0) 64%, var(--white-500) 95%, var(--white-500) 100%);
                pointer-events: none;
            }

            .title {
                font: var(--font-h4);
                font-weight: bold;
                color: var(--dark-500);
            }

            .description {
                font: var(--font-body-1);
                color: var(--dark-500);
                text-shadow: 0 0 8px var(--white-500);
            }

            .code {
                font: var(--font-h3);
                color: var(--dark-500);
                text-shadow: 0 0 8px var(--white-500);
            }

            .instruction {
                font: var(--font-body-1);
                color: var(--dark-500);
                text-shadow: 0 0 8px var(--white-500);
            }

            .warning {
                font: var(--font-body-1);
                color: var(--secondary-500);
                text-shadow: 0 0 8px var(--white-500);
            }

            & > ul {
                margin: auto auto 0;
                z-index: 1;
            }

            & > button {
                border-radius: 50%;;
            }

            .enter-box {
                margin-top: auto;
                display: flex;
                flex-direction: column;
                align-items: center;
                width: 100%;
                z-index: 1;
                flex: 0;
                gap: 10px;
                // div {
                //     margin-top: auto;
                //     display: inline;
                //     span {
                //         font: var(--font-caption);
                //         color: var(--dark-500);
                //         text-align: center;
                //         display: flex;
                //         flex-direction: column;
                //         gap: 0;
                //     }
                // }
                button {
                    // flex: 1 1 100%;
                    width: 100%;
                    flex-shrink: 0;
                }
            }


            &.last-child {
                .title,
                .description {
                    opacity: 0;
                }
            }
        }

        @keyframes fadeIn {
            to {
                opacity: 1;
            }
        }
    }
    
</style>
